import os
import sys
import shutil
import zipfile
import tarfile
import subprocess
import argparse
from pathlib import Path

def create_tar_gz(source_dir, output_file):
    with tarfile.open(output_file, "w:gz") as tar:
        tar.add(source_dir, arcname=os.path.basename(source_dir))

def create_tar_bz2(source_dir, output_file):
    with tarfile.open(output_file, "w:bz2") as tar:
        tar.add(source_dir, arcname=os.path.basename(source_dir))

def create_zip(source_dir, output_file):
    with zipfile.ZipFile(output_file, 'w', zipfile.ZIP_DEFLATED) as zipf:
        for root, dirs, files in os.walk(source_dir):
            for file in files:
                file_path = os.path.join(root, file)
                arc_path = os.path.relpath(file_path, source_dir)
                zipf.write(file_path, arc_path)

def create_7z(source_dir, output_file):
    try:
        subprocess.run(['7z', 'a', '-y', output_file, source_dir], check=True, 
                      stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    except (subprocess.CalledProcessError, FileNotFoundError):
        raise Exception("7z command not found or failed")

def backup_directory(source_dir, format_type, output_file):
    source_dir = os.path.abspath(source_dir)
    
    if not os.path.exists(source_dir):
        raise Exception(f"Source directory does not exist: {source_dir}")
    
    if not os.path.isdir(source_dir):
        raise Exception(f"Source path is not a directory: {source_dir}")
    
    # Validate format type
    allowed_formats = ['tar.gz', 'tar.bz2', 'zip', '7z']
    if format_type not in allowed_formats:
        raise Exception(f"Unsupported format. Use one of: {allowed_formats}")
    
    # Validate output file path
    output_path = Path(output_file)
    output_path.parent.mkdir(parents=True, exist_ok=True)
    
    # Create backup based on format
    if format_type == 'tar.gz':
        create_tar_gz(source_dir, output_file)
    elif format_type == 'tar.bz2':
        create_tar_bz2(source_dir, output_file)
    elif format_type == 'zip':
        create_zip(source_dir, output_file)
    elif format_type == '7z':
        create_7z(source_dir, output_file)

def main():
    parser = argparse.ArgumentParser(description='Backup directory to compressed archive')
    parser.add_argument('source_dir', help='Directory to backup')
    parser.add_argument('format', choices=['tar.gz', 'tar.bz2', 'zip', '7z'], 
                       help='Compression format')
    parser.add_argument('output_file', help='Output archive file path')
    
    args = parser.parse_args()
    
    try:
        backup_directory(args.source_dir, args.format, args.output_file)
        print(f"Backup completed successfully: {args.output_file}")
    except Exception as e:
        print(f"Error: {str(e)}")
        sys.exit(1)

if __name__ == "__main__":
    main()